package com.hospital.management.util;import java.sql.*;import java.time.Year;/** Generates ADM-YYYY-NNNNNN values from Oracle ADMISSION_NUMBER_SEQ. */public class AdmissionNumberGenerator{public String next(Connection c)throws SQLException{try(PreparedStatement s=c.prepareStatement("SELECT ADMISSION_NUMBER_SEQ.NEXTVAL FROM DUAL");ResultSet r=s.executeQuery()){if(!r.next())throw new SQLException("Admission sequence returned no value");return"ADM-"+Year.now().getValue()+"-"+String.format("%06d",r.getLong(1));}}}
